const LOCKFILES = new Set([
  "package-lock.json",
  "yarn.lock",
  "pnpm-lock.yaml",
  "bun.lockb",
  "bun.lock",
  "cargo.lock",
  "poetry.lock",
  "pipfile.lock",
  "go.sum",
  "composer.lock",
  "gemfile.lock",
  "packages.lock.json",
  "uv.lock",
]);

const CONFIG_BASENAMES = new Set([
  "package.json", "tsconfig.json", "jsconfig.json", "pyproject.toml", "setup.py",
  "setup.cfg", "requirements.txt", "pipfile", "cargo.toml", "go.mod", "composer.json",
  "gemfile", "makefile", "cmakelists.txt", "dockerfile", "docker-compose.yml",
  "docker-compose.yaml", "compose.yml", "compose.yaml", ".env.example", "turbo.json",
  "nx.json", "lerna.json", "pnpm-workspace.yaml", "vercel.json", "netlify.toml",
  "next.config.js", "next.config.mjs", "next.config.ts", "vite.config.ts",
  "vite.config.js", "webpack.config.js", "rollup.config.js", "babel.config.js",
  ".eslintrc.json", ".prettierrc", "eslint.config.js", "eslint.config.mjs",
]);

const DOC_EXTENSIONS = new Set([".md", ".mdx", ".rst", ".txt", ".adoc"]);
const DATA_EXTENSIONS = new Set([".json", ".yaml", ".yml", ".toml", ".xml", ".csv", ".ini", ".proto", ".graphql", ".sql"]);
const SOURCE_EXTENSIONS = new Set([
  ".c", ".cc", ".cpp", ".cs", ".css", ".dart", ".ex", ".exs", ".fs", ".fsx",
  ".go", ".h", ".hpp", ".html", ".java", ".js", ".jsx", ".kt", ".kts", ".lua",
  ".m", ".mm", ".php", ".pl", ".py", ".r", ".rb", ".rs", ".scala", ".scss",
  ".sh", ".sol", ".svelte", ".swift", ".ts", ".tsx", ".vue", ".zig",
]);
const SOURCE_BASENAMES = new Set(["rakefile", "procfile", "justfile"]);

const SECRET_PATTERNS: Array<[RegExp, string]> = [
  [/-----BEGIN (?:RSA |EC |OPENSSH |DSA )?PRIVATE KEY-----[\s\S]*?-----END (?:RSA |EC |OPENSSH |DSA )?PRIVATE KEY-----/g, "[REDACTED_PRIVATE_KEY]"],
  [/\bgh[pousr]_[A-Za-z0-9_]{20,}\b/g, "[REDACTED_GITHUB_TOKEN]"],
  [/\bgithub_pat_[A-Za-z0-9_]{20,}\b/g, "[REDACTED_GITHUB_TOKEN]"],
  [/\bsk-(?:proj-)?[A-Za-z0-9_-]{20,}\b/g, "[REDACTED_API_KEY]"],
  [/\bAKIA[0-9A-Z]{16}\b/g, "[REDACTED_AWS_KEY]"],
  [/\b(?:postgres(?:ql)?|mysql|mongodb(?:\+srv)?):\/\/[^\s:@/]+:[^\s@/]+@/gi, "[REDACTED_DATABASE_URL]"],
];

export const MAX_FILE_BYTES = 1024 * 1024; // >1MB: skip entirely
export const SKELETON_ONLY_BYTES = 100 * 1024; // 100KB-1MB: skeleton only, never full source

const GENERATED_MARKERS = [
  "@generated",
  "do not edit",
  "code generated by",
  "auto-generated",
  "autogenerated",
  "this file was generated",
  "generated automatically",
];

export function createIgnoreFilter(extraGlobs: string[] = []): Ignore {
  return ignore().add(DEFAULT_IGNORE_PATTERNS).add(extraGlobs);
}

function extOf(path: string): string {
  const base = path.split("/").pop() ?? "";
  const i = base.lastIndexOf(".");
  return i >= 0 ? base.slice(i).toLowerCase() : "";
}

function basenameOf(path: string): string {
  return (path.split("/").pop() ?? "").toLowerCase();
}

export function looksBinary(buf: Buffer): boolean {
  const n = Math.min(buf.length, 8192);
  for (let i = 0; i < n; i++) if (buf[i] === 0) return true;
  return false;
}

function looksGenerated(content: string): boolean {
  const head = content.slice(0, 2000).toLowerCase();
  if (GENERATED_MARKERS.some((m) => head.includes(m))) return true;
  // minification heuristic: very long average line length
  const lines = content.split("\n");
  if (lines.length > 3) {
    const avg = content.length / lines.length;
    if (avg > 250) return true;
  }
  return false;
}

export type ClassifyInput = {
  path: string; // repo-relative, forward slashes
  sizeBytes: number;
  ig: Ignore;
  /** lazily-read content; only called when path/size checks pass */
  getContent: () => Buffer;
};

export type ClassifyResult = {
  kind: FileKind;
  /** content is only kept for kinds that go to storage/analysis */
  content?: string;
};

/** Defense-in-depth redaction for allowed text files before persistence or LLM use. */
export function redactSecrets(content: string): { content: string; redactions: number } {
  let redactions = 0;
  let clean = content;
  for (const [pattern, replacement] of SECRET_PATTERNS) {
    clean = clean.replace(pattern, (...args) => {
      redactions++;
      return replacement;
    });
  }
  return { content: clean, redactions };
}

/**
 * Deterministic classification, cheapest checks first.
 * Only kinds source|config|doc keep content and ever reach the LLM.
 */
export async function classifyFile(input: ClassifyInput): Promise<ClassifyResult> {
  const { path, sizeBytes, ig } = input;
  const base = basenameOf(path);

  if (ig.ignores(path)) return { kind: "ignored" };
  if (LOCKFILES.has(base)) return { kind: "data" }; // existence recorded, content dropped
  if (sizeBytes > MAX_FILE_BYTES) return { kind: "ignored" };
  if (sizeBytes === 0) return { kind: "ignored" };

  const buf = input.getContent();
  if (looksBinary(buf)) return { kind: "binary" };
  const decoded = buf.toString("utf8");
  const fastRedacted = redactSecrets(decoded).content;
  const content = (await scanAndRedactSecrets(fastRedacted, path)).content;

  const ext = extOf(path);
  if (CONFIG_BASENAMES.has(base)) return { kind: "config", content };
  if (DOC_EXTENSIONS.has(ext)) return { kind: "doc", content };

  if (looksGenerated(content)) return { kind: "generated" };
  if (DATA_EXTENSIONS.has(ext)) {
    // data files: keep small ones (may be schema/fixtures worth mentioning), drop big
    return sizeBytes <= 32 * 1024 ? { kind: "data", content } : { kind: "data" };
  }

  if (SOURCE_EXTENSIONS.has(ext) || SOURCE_BASENAMES.has(base)) {
    return { kind: "source", content };
  }
  return { kind: "ignored" };
}
